const child = $input.item.json;
const SB_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk';
const headers = { 'apikey': SB_KEY, 'Authorization': 'Bearer ' + SB_KEY };
const SB = 'https://jmdyhxebcosyjyafzsss.supabase.co';
const now = new Date();
const todayUTC = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
const sevenDaysAgo = new Date(todayUTC.getTime() - 7 * 86400000);
let sessions = [], reactions = [], dynamicContext = {}, previousBrief = null, pushSubscription = null;
try {
  sessions = await this.helpers.httpRequest({ method: 'GET', url: SB + '/rest/v1/story_sessions?child_id=eq.' + child.id + '&created_at=gte.' + sevenDaysAgo.toISOString() + '&created_at=lt.' + todayUTC.toISOString() + '&order=created_at.asc&select=*', headers }) || [];
} catch(e) { console.log('Sessions error:', e.message); }
if (!Array.isArray(sessions) || sessions.length < 3) {
  return { has_minimum_sessions: false, session_count: Array.isArray(sessions) ? sessions.length : 0, child };
}
try {
  reactions = await this.helpers.httpRequest({ method: 'GET', url: SB + '/rest/v1/morning_reactions?child_id=eq.' + child.id + '&generated_at=gte.' + sevenDaysAgo.toISOString() + '&select=observations,reactions,night_type,skipped,generated_at', headers }) || [];
} catch(e) { console.log('Reactions error:', e.message); }
try {
  const ctx = await this.helpers.httpRequest({ method: 'GET', url: SB + '/rest/v1/child_dynamic_context?child_id=eq.' + child.id + '&limit=1&select=*', headers });
  dynamicContext = Array.isArray(ctx) && ctx.length > 0 ? ctx[0] : {};
} catch(e) {}
try {
  const briefs = await this.helpers.httpRequest({ method: 'GET', url: SB + '/rest/v1/weekly_briefs?child_id=eq.' + child.id + '&order=created_at.desc&limit=1&select=brief_text,week_start', headers });
  previousBrief = Array.isArray(briefs) && briefs.length > 0 ? briefs[0] : null;
} catch(e) {}
try {
  const prefs = await this.helpers.httpRequest({ method: 'GET', url: SB + '/rest/v1/notification_preferences?user_id=eq.' + child.user_id + '&child_id=eq.' + child.id + '&limit=1&select=push_subscription', headers });
  pushSubscription = Array.isArray(prefs) && prefs.length > 0 ? prefs[0].push_subscription : null;
} catch(e) {}
return { has_minimum_sessions: true, sessions, reactions, dynamicContext, previousBrief, pushSubscription, child, week_start: sevenDaysAgo.toISOString() };

if (!$input.item.json.has_minimum_sessions) { return { skipped: true }; }
const { sessions, reactions, dynamicContext: ctx, previousBrief, pushSubscription, child, week_start } = $input.item.json;
const coCount = sessions.filter(s => s.night_type === 'co_creation').length;
const pbCount = sessions.filter(s => s.night_type === 'playback').length;
const total = sessions.length;
const sessionLines = sessions.map(s => {
  const d = new Date(s.created_at).toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' });
  return s.night_type === 'playback'
    ? '- ' + d + ' | PLAYBACK | Story: "' + (s.source_story_title || 'Unknown') + '" | Played ' + (s.playback_count_14d != null ? s.playback_count_14d : '?') + 'x in 14 days | Note: ' + (s.parent_note || 'None')
    : '- ' + d + ' | CO-CREATION | Prompt: "' + (s.story_prompt || 'None') + '" | Themes: ' + ((s.themes || []).join(', ') || 'None') + ' | Note: ' + (s.parent_note || 'None');
}).join('
');
const reactionSummary = reactions.length > 0
  ? reactions.map(r => {
      if (r.skipped) return '- [SKIPPED]';
      const lines = (r.observations || []).map((o, i) => {
        const rxn = (r.reactions || [])[i];
        const label = rxn === 'noticed' ? 'Noticed' : rxn === 'unsure' ? 'Not sure' : rxn === 'didnt_see' ? 'Didnt see' : 'no reaction';
        return '  ' + o.type + ': "' + o.text + '" -> ' + label;
      }).join('
');
      return '[' + r.night_type + ']
' + lines;
    }).join('
')
  : 'No morning reactions this week.';
const allies = (ctx.characters || []).filter(c => c.name).map(c => c.name + ' (' + (c.role || 'ally') + ')').join(', ') || 'None noted';
const systemPrompt = 'You are a compassionate child development observer writing a weekly brief for a parent. Plain language, warm, non-alarmist. Never clinical, never diagnostic.

Structure your response with exactly these three labelled sections:

HIGHLIGHTS
2-4 sentences. The most significant emotional or thematic story across this weeks sessions. Must be specific to this child and this week.

PATTERNS
2-4 sentences. Only name a pattern if at least two separate nights point in the same direction. If no genuine pattern exists write: Nothing clear enough to name this week. If the child had more playback nights than co-creation nights, name that explicitly.

WHAT TO WATCH
2 sentences. One specific forward-looking lens for the parent. Not a task — something to notice.

Maximum 200 words total. Weight observations that received parent Noticed this reactions more heavily. Do not repeat last weeks brief unless there is clear continuation.';
const userPrompt = 'CHILD: ' + child.name + ', age ' + child.age + (child.gender_pronoun ? ', pronouns: ' + child.gender_pronoun : '') + '.
Personality: ' + (child.personality_description || 'Not provided') + '.
Neuro profile: ' + (child.neuro_profile || 'Not specified') + '. Flags: ' + ((child.neuro_flags || []).join(', ') || 'None') + '.
Interests: ' + ((child.interests || []).join(', ') || 'Not specified') + '.
Family: ' + (child.family_structure || 'Not provided') + '.
Fear landscape: ' + ((ctx.fear_flags || []).join(', ') || 'None noted') + '.
Current stressors: ' + (ctx.current_stressors || 'None noted') + '.
Allies: ' + allies + '.

SESSIONS THIS WEEK (' + total + ' total, ' + coCount + ' co-creation, ' + pbCount + ' playback):
' + sessionLines + '

MORNING REACTIONS THIS WEEK:
' + reactionSummary + '

LAST WEEKS BRIEF:
' + (previousBrief ? 'Week of ' + previousBrief.week_start + ': ' + previousBrief.brief_text : 'No previous brief — this is the first week.') + '

Write the weekly brief now.';
return { systemPrompt, userPrompt, child_id: child.id, user_id: child.user_id, child_name: child.name, week_start: week_start.split('T')[0], total_nights: total, co_creation_nights: coCount, playback_nights: pbCount, pushSubscription };

if ($input.item.json.skipped) { return { skipped: true }; }
const claudeResponse = $input.item.json;
const prev = $('Build Brief Prompt').item.json;
const briefText = claudeResponse.content && claudeResponse.content[0] ? claudeResponse.content[0].text : '';
if (!briefText) { return { error: 'Claude returned empty brief' }; }
const SB_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk';
const headers = { 'apikey': SB_KEY, 'Authorization': 'Bearer ' + SB_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' };
await this.helpers.httpRequest({ method: 'POST', url: 'https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/weekly_briefs', headers, body: JSON.stringify({ child_id: prev.child_id, user_id: prev.user_id, brief_content: { text: briefText, co_creation_nights: prev.co_creation_nights, playback_nights: prev.playback_nights }, brief_text: briefText, week_start_date: prev.week_start, week_end_date: new Date().toISOString().split('T')[0], week_start: prev.week_start, session_count: prev.total_nights, total_nights: prev.total_nights, co_creation_nights: prev.co_creation_nights, playback_nights: prev.playback_nights, status: 'delivered', delivered_at: new Date().toISOString() }) });
if (prev.pushSubscription) {
  try {
    await this.helpers.httpRequest({ method: 'POST', url: $vars.PUSH_LAMBDA_URL, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ subscription: prev.pushSubscription, payload: { title: prev.child_name + "'s weekly brief is ready", body: "This week's bedtime patterns — tap to read.", tag: 'weekly-brief', data: { type: 'weekly_brief', child_id: prev.child_id } } }) });
  } catch(e) { console.log('Push failed:', e.message); }
}
return { done: true, child_id: prev.child_id };
